import sys
sys.setrecursionlimit(20000)
n=int(input())
p=list(map(int,input().split()))
children=[[] for _ in range(n)]
root=-1
for i,par in enumerate(p):
    if par==-1:root=i
    else:children[par].append(i)
def height(u):
    if not children[u]:return 0
    return 1+max(height(c) for c in children[u])
print(height(root))

